const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

try {
  // 定义可能存放日志的系统目录 (囊括常规部署的路径)
  const logDirs = ['/app/vertex/logs', '/vertex/logs', '/app/vertex/data/logs'];
  const keepDays = 5; // 【参数】只保留最近 5 天的日志，再老的全干掉
  const now = Date.now();
  let deleteCount = 0;

  // 1. 扫描并收割老旧日志
  for (const dir of logDirs) {
    if (fs.existsSync(dir)) {
      const files = fs.readdirSync(dir);
      for (const file of files) {
        const filePath = path.join(dir, file);
        const stats = fs.statSync(filePath);

        // 计算文件最后修改时间距今多少天
        const daysOld = (now - stats.mtimeMs) / (1000 * 60 * 60 * 24);

        // 非目录文件且超过 5 天就无情删掉
        if (daysOld > keepDays && stats.isFile()) {
           fs.unlinkSync(filePath);
           deleteCount++;
        }
      }
    }
  }

  // 2. 清理 Vertex 容器运行时的零碎临时垃圾文件 (由于是在容器化隔离内，这么干绝对安全)
  try {
    execSync('rm -rf /tmp/*');
  } catch(e) {}

  // 打印一条绿色的成功日志
  logger.info(`[空间保洁] 打扫完成！删除了 ${deleteCount} 个过期日志，并清空了临时缓存。这下 2% 的救命空间永远花不完了！`);
} catch (err) {
  logger.error(`[空间保洁] 运行报错: ${err.message}`);
}
